// Extract search query from NEXUS payload
// Handle both direct webhook and sub-workflow calls
const raw = $input.first().json;
const data = raw.body || raw;
const ideaPrompt = data.ideaPrompt || '';
const briefId = data.briefId || '';
const departments = data.departments || [];

// Build focused search queries
const baseQuery = ideaPrompt.slice(0, 120);
const queries = [
  baseQuery,
  `${baseQuery} typescript react`,
  `${baseQuery} nodejs express`
];

return [{ json: { briefId, ideaPrompt, queries, departments } }];

// Process GitHub search results and calculate Trust Scores
const items = $input.first().json;
const repos = items.items || [];
const briefId = $('Extract Search Query').first().json.briefId;
const callbackUrl = $('Extract Search Query').first().json.callbackUrl;

const sources = repos.slice(0, 5).map(repo => {
  const stars = repo.stargazers_count || 0;
  const contributors = repo.contributors_count || repo.forks_count || 1;

  // Trust Score formula matching NEXUS: log10(stars+1)*20 + log10(contributors+1)*10
  const trustScore = Math.min(100, Math.round(
    Math.log10(stars + 1) * 20 + Math.log10(contributors + 1) * 10
  ));

  return {
    sourceType: 'github',
    url: repo.html_url,
    title: `${repo.full_name} — ${repo.description || 'No description'}`.slice(0, 500),
    snippet: `⭐ ${stars.toLocaleString()} stars | 🍴 ${repo.forks_count} forks | Language: ${repo.language || 'N/A'} | Updated: ${repo.updated_at?.split('T')[0] || 'Unknown'}`,
    trustScore,
    githubStars: stars,
    contributorCount: contributors,
    rawPayload: {
      source: 'n8n',
      workflowType: 'github_research',
      fullName: repo.full_name,
      language: repo.language,
      topics: repo.topics,
      license: repo.license?.spdx_id,
      openIssues: repo.open_issues_count,
      createdAt: repo.created_at,
      updatedAt: repo.updated_at
    }
  };
});

return [{ json: {
  sources,
  metadata: {
    workflowName: 'nexus-github-research',
    durationMs: Date.now(),
    totalRepos: repos.length,
    briefId
  }
}}];
